// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TokenVoting {
    address private _owner;
    uint256 private _candidateCount;
    mapping(uint256 => string) private _candidateNames;
    mapping(uint256 => uint256) private _candidateVotes;
    mapping(address => bool) private _voters;
    mapping(uint256 => bool) private _isVoted;

    constructor() {
        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not the owner");
        _;
    }

    function candidateCount() public view returns (uint256) {
        return _candidateCount;
    }

    function candidateNames(uint256 id) public view returns (string memory) {
        require(id < _candidateCount, "Invalid candidate ID");
        return _candidateNames[id];
    }

    function candidateVotes(uint256 id) public view returns (uint256) {
        require(id < _candidateCount, "Invalid candidate ID");
        return _candidateVotes[id];
    }

    function addCandidate(string memory name) public onlyOwner {
        _candidateNames[_candidateCount] = name;
        _candidateVotes[_candidateCount] = 0;
        _candidateCount++;
    }

    function grantVotingRights(address voter) public onlyOwner {
        _voters[voter] = true;
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return _voters[voter];
    }

    function vote(uint256 candidateId) public {
        require(hasVotingRights(msg.sender), "No voting rights");
        require(candidateId < _candidateCount, "Invalid candidate ID");
        require(!_isVoted[candidateId], "Already voted for this candidate");

        _isVoted[candidateId] = true;
        _candidateVotes[candidateId]++;
    }
}
